var surah068 = {
  number: 68,
  nameArabic: "al-Qalam",
  nameEnglish: "Al-Qalam",
  meaning: "The Pen",
  totalAyahs: 52,
  ayahs: [
    { number: 1, arabic: "نٓ ۚ وَٱلْقَلَمِ وَمَا يَسْطُرُونَ", transliteration: "Noon waalqalami wama yasturoona", transliterationB: "Noon; walqalami wa maa yasturoon", english: "Nun. By the Pen and the (Record) which (men) write", romanUrdu: "Noon, Kasam hai qalam ki aur us cheez ki jisey likhne waley likh rahey hain" },
    { number: 2, arabic: "مَآ أَنتَ بِنِعْمَةِ رَبِّكَ بِمَجْنُونٍۢ", transliteration: "Ma anta biniAAmati rabbika bimajnoonin", transliterationB: "Maa anta bini'mati Rabbika bimajnoon", english: "Thou art not, by the Grace of thy Lord, mad or possessed", romanUrdu: "Tum apne Rubb ke fazl se majnoon (deewane) nahin ho" },
    { number: 3, arabic: "وَإِنَّ لَكَ لَأَجْرًا غَيْرَ مَمْنُونٍۢ", transliteration: "Wainna laka laajran ghayra mamnoonin", transliterationB: "Wa inna laka la ajran ghaira mamnoon", english: "Nay, verily for thee is a Reward unfailing", romanUrdu: "Aur yaqeenan tumhare liye aisa ajar (reward) hai jiska silsila kabhi khatm honay wala nahin" },
    { number: 4, arabic: "وَإِنَّكَ لَعَلَىٰ خُلُقٍ عَظِيمٍۢ", transliteration: "Wainnaka laAAala khuluqin AAatheemin", transliterationB: "Wa innaka la'alaa khuluqin 'azeem", english: "And thou (standest) on an exalted standard of character", romanUrdu: "Aur beshak tum akhlaaq ke bade martabe par ho" },
    { number: 5, arabic: "فَسَتُبْصِرُ وَيُبْصِرُونَ", transliteration: "Fasatubsiru wayubsiroona", transliterationB: "Fasatubsiru wa yubsiroon", english: "Soon wilt thou see, and they will see", romanUrdu: "Anqareeb tum bhi dekh logey aur woh bhi dekh lenge" },
    { number: 6, arabic: "بِأَييِّكُمُ ٱلْمَفْتُونُ", transliteration: "Biayyikumu almaftoonu", transliterationB: "Bi ayyikumul maftoon", english: "Which of you is afflicted with madness", romanUrdu: "Ke tum mein se kaun junoon (madness) mein mubtala hai" },
    { number: 7, arabic: "إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ", transliteration: "Inna rabbaka huwa aAAlamu biman dalla AAan sabeelihi wahuwa aAAlamu bialmuhtadeena", transliterationB: "Innaa Rabbaka Huwa a'lamu biman dalla 'an sabeelihee wa Huwa a'lamu bilmuhtadeen", english: "Verily it is thy Lord that knoweth best, which (among men) hath strayed from His Path: and He knoweth best those who receive (true) Guidance", romanUrdu: "Tumhara Rubb un logon ko bhi khoob jaanta hai jo uski raah se bhatkey huey hain , aur wahi unko bhi acchi tarah jaanta hai jo raah-e-raast par hai" },
    { number: 8, arabic: "فَلَا تُطِعِ ٱلْمُكَذِّبِينَ", transliteration: "Fala tutiAAi almukaththibeena", transliterationB: "Falaa tuti'il mukazzibeen", english: "So hearken not to those who deny (the Truth)", romanUrdu: "Lihaza tum in jhutlane walon ke dabao mein hargiz na aao" },
    { number: 9, arabic: "وَدُّوا۟ لَوْ تُدْهِنُ فَيُدْهِنُونَ", transliteration: "Waddoo law tudhinu fayudhinoona", transliterationB: "Waddoo law tudhinu fa-yudhinoon", english: "Their desire is that thou shouldst be pliant: so would they be pliant", romanUrdu: "yeh to chahte hain ke kuch tum mudahnat (narmi) karo to yeh bhi mudahnat (narmi) karein" },
    { number: 10, arabic: "وَلَا تُطِعْ كُلَّ حَلَّافٍۢ مَّهِينٍ", transliteration: "Wala tutiAA kulla hallafin maheenin", transliterationB: "Wa laa tuti' kulla hallaa fim maheen", english: "Heed not the type of despicable men,- ready with oaths", romanUrdu: "Hargiz na dabo kisi aisey shaks se jo bahut kasmein khane wala be-waqaat (worthless) aadmi hai" },
    { number: 11, arabic: "هَمَّازٍۢ مَّشَّآءٍۭ بِنَمِيمٍۢ", transliteration: "Hammazin mashshain binameemin", transliterationB: "Hammaazim mash shaaa'im binameem", english: "A slanderer, going about with calumnies", romanUrdu: "Taaney deta hai , chugliyan khata phirta hai (slanderer, gossip-monger)" },
    { number: 12, arabic: "مَّنَّاعٍۢ لِّلْخَيْرِ مُعْتَدٍ أَثِيمٍ", transliteration: "MannaAAin lilkhayri muAAtadin atheemin", transliterationB: "Mannaa'il lilkhairi mu'tadin aseem", english: "(Habitually) hindering (all) good, transgressing beyond bounds, deep in sin", romanUrdu: "Bhalayi se rokta hai , zulm-o-zyadti mein hadd se guzar janey wala hai, sakht badh-amal hai , jafa-kaar hai" },
    { number: 13, arabic: "عُتُلٍّۭ بَعْدَ ذَٰلِكَ زَنِيمٍ", transliteration: "AAutullin baAAda thalika zaneemin", transliterationB: "Utullim ba'da zaalika zaneem", english: "Violent (and cruel),- with all that, base-born", romanUrdu: "Aur in sab uyub (aib) ke saath badh-asl (illegitimate child) hai" },
    { number: 14, arabic: "أَن كَانَ ذَا مَالٍۢ وَبَنِينَ", transliteration: "An kana tha malin wabaneena", transliterationB: "An kaana zaa maalinw-wa baneen", english: "Because he possesses wealth and (numerous) sons", romanUrdu: "Is bina par ke woh bahut maal-o-aulad rakhta hai" },
    { number: 15, arabic: "إِذَا تُتْلَىٰ عَلَيْهِ ءَايَٰتُنَا قَالَ أَسَٰطِيرُ ٱلْأَوَّلِينَ", transliteration: "Itha tutla AAalayhi ayatuna qala asateeru alawwaleena", transliterationB: "Izaa tutlaa 'alaihi aayaatunaa qaala asaateerul awwaleen", english: "When to him are rehearsed Our Signs, \"Tales of the ancients\", he cries", romanUrdu: "Jab hamari aayat usko sunayi jati hai to kehta hai yeh to agle waqton ke afsane hain" },
    { number: 16, arabic: "سَنَسِمُهُۥ عَلَى ٱلْخُرْطُومِ", transliteration: "Sanasimuhu AAala alkhurtoomi", transliterationB: "Sanasimuhoo 'alal khurtoom", english: "Soon shall We brand (the beast) on the snout", romanUrdu: "Ankareeb hum iski sund (snout) par daag lagayenge" },
    { number: 17, arabic: "إِنَّا بَلَوْنَٰهُمْ كَمَا بَلَوْنَآ أَصْحَٰبَ ٱلْجَنَّةِ إِذْ أَقْسَمُوا۟ لَيَصْرِمُنَّهَا مُصْبِحِينَ", transliteration: "Inna balawnahum kama balawna ashaba aljannati ith aqsamoo layasrimunnaha musbiheena", transliterationB: "Innaa balawnaahum kamaa balawnaaa As-haabal jannati iz 'aqsamoo la-yasri munnahaa musbiheen", english: "Verily We have tried them as We tried the People of the Garden, when they resolved to gather the fruits of the (garden) in the morning", romanUrdu: "Humne in (ehle makkah) ko usi taraah aazmaish mein dala hai jis tarah ek baagh (garden) ke maalikon ko aazmaish mein dala tha, jab unhon ne kasam khayi ke subah sawerey zaroor apne baagh ke phal todenge" },
    { number: 18, arabic: "وَلَا يَسْتَثْنُونَ", transliteration: "Wala yastathnoona", transliterationB: "Wa laa yastasnoon", english: "But made no reservation, (\"If it be Allah's Will)", romanUrdu: "Aur woh koi istasna (exception) nahin kar rahey thay" },
    { number: 19, arabic: "فَطَافَ عَلَيْهَا طَآئِفٌۭ مِّن رَّبِّكَ وَهُمْ نَآئِمُونَ", transliteration: "Fatafa AAalayha taifun min rabbika wahum naimoona", transliterationB: "Fataafa 'alaihaa taaa'i fum mir rabbika wa hum naaa'imoon", english: "Then there came on the (garden) a visitation from thy Lord, (which swept away) all around, while they were asleep", romanUrdu: "Raat ko woh soye padey thay ke tumhare Rubb ki taraf se ek balaa is baagh par phir gayi" },
    { number: 20, arabic: "فَأَصْبَحَتْ كَٱلصَّرِيمِ", transliteration: "Faasbahat kaalssareemi", transliterationB: "Fa asbahat kassareem", english: "So the (garden) became, by the morning, like a dark and desolate spot, (whose fruit had been gathered)", romanUrdu: "Aur uska haal aisa ho gaya jaise kati hui fasal ho" },
    { number: 21, arabic: "فَتَنَادَوْا۟ مُصْبِحِينَ", transliteration: "Fatanadaw musbiheena", transliterationB: "Fatanaadaw musbiheen", english: "As the morning broke, they called out, one to another", romanUrdu: "Subah un logon ne ek dusre ko pukara" },
    { number: 22, arabic: "أَنِ ٱغْدُوا۟ عَلَىٰ حَرْثِكُمْ إِن كُنتُمْ صَٰرِمِينَ", transliteration: "Ani ighdoo AAala harthikum in kuntum sarimeena", transliterationB: "Anighdoo 'alaa harsikum in kuntum saarimeen", english: "Go ye to your tilth (betimes) in the morning, if ye would gather the fruits", romanUrdu: "Kaha agar phal todne hai ho to sawerey sawerey apni kheti ki taraf nikal chalo" },
    { number: 23, arabic: "فَٱنطَلَقُوا۟ وَهُمْ يَتَخَٰفَتُونَ", transliteration: "Faintalaqoo wahum yatakhafatoona", transliterationB: "Fantalaqoo wa hum yatakhaafatoon", english: "So they departed, conversing in secret low tones, (saying)", romanUrdu: "Chunanchey woh chal padey aur aapas mein chupke chupke kehte jatay thay" },
    { number: 24, arabic: "أَن لَّا يَدْخُلَنَّهَا ٱلْيَوْمَ عَلَيْكُم مِّسْكِينٌۭ", transliteration: "An la yadkhulannaha alyawma AAalaykum miskeenun", transliterationB: "Al laa yadkhulannahal yawma 'alaikum miskeen", english: "Let not a single indigent person break in upon you into the (garden) this day", romanUrdu: "Ke aaj koi miskeen tumhare paas baag mein na aane paye" },
    { number: 25, arabic: "وَغَدَوْا۟ عَلَىٰ حَرْدٍۢ قَٰدِرِينَ", transliteration: "Waghadaw AAala hardin qadireena", transliterationB: "Wa ghadaw 'alaa hardin qaadireen", english: "And they opened the morning, strong in an (unjust) resolve", romanUrdu: "Woh kuch na dene ka faisla kiye huye subah sawerey jaldi jaldi is tarah wahan gaye jaise ke woh (phal todne par) qadir hain" },
    { number: 26, arabic: "فَلَمَّا رَأَوْهَا قَالُوٓا۟ إِنَّا لَضَآلُّونَ", transliteration: "Falamma raawha qaloo inna ladalloona", transliterationB: "Falammaa ra awhaa qaalooo innaa ladaaalloon", english: "But when they saw the (garden), they said: \"We have surely lost our way", romanUrdu: "Magar jab baagh ko dekha to kehne lagey “hum raasta bhool gaye hain" },
    { number: 27, arabic: "بَلْ نَحْنُ مَحْرُومُونَ", transliteration: "Bal nahnu mahroomoona", transliterationB: "Bal nahnu mahroomoon", english: "Indeed we are shut out (of the fruits of our labour)", romanUrdu: "Nahin balke hum mehroom reh gaye”" },
    { number: 28, arabic: "قَالَ أَوْسَطُهُمْ أَلَمْ أَقُل لَّكُمْ لَوْلَا تُسَبِّحُونَ", transliteration: "Qala awsatuhum alam aqul lakum lawla tusabbihoona", transliterationB: "Qaala awsatuhum alam aqul lakum law laa tusabbihoon", english: "Said one of them, more just (than the rest): \"Did I not say to you, 'Why not glorify (Allah)", romanUrdu: "Un mein jo sab se behtar aadmi tha usne kaha “maine tumse kaha na tha ke tum tasbeeh kyun nahin karte?”" },
    { number: 29, arabic: "قَالُوا۟ سُبْحَٰنَ رَبِّنَآ إِنَّا كُنَّا ظَٰلِمِينَ", transliteration: "Qaloo subhana rabbina inna kunna thalimeena", transliterationB: "Qaaloo subhaana rabbinaaa innaa kunnaa zaalimeen", english: "They said: \"Glory to our Lord! Verily we have been doing wrong", romanUrdu: "Woh pukar utthey paak hai hamara Rubb, waqayi hum gunahgaar thay" },
    { number: 30, arabic: "فَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍۢ يَتَلَٰوَمُونَ", transliteration: "Faaqbala baAAduhum AAala baAAdin yatalawamoona", transliterationB: "Fa aqbala ba'duhum 'alaa ba'diny yatalaawamoon", english: "Then they turned, one against another, in reproach", romanUrdu: "Phir unmein se har ek dusre ko malamat karne laga" },
    { number: 31, arabic: "قَالُوا۟ يَٰوَيْلَنَآ إِنَّا كُنَّا طَٰغِينَ", transliteration: "Qaloo ya waylana inna kunna tagheena", transliterationB: "Qaaloo yaa wailanaaa innaa kunnaa taagheen", english: "They said: \"Alas for us! We have indeed transgressed", romanUrdu: "Akhir ko unhon ne kaha “afsos hamare haal par, beshak hum sarkash ho gaye thay" },
    { number: 32, arabic: "عَسَىٰ رَبُّنَآ أَن يُبْدِلَنَا خَيْرًۭا مِّنْهَآ إِنَّآ إِلَىٰ رَبِّنَا رَٰغِبُونَ", transliteration: "AAasa rabbuna an yubdilana khayran minha inna ila rabbina raghiboona", transliterationB: "Asaa rabbunaaa any yubdilanaa khairam minhaaa innaaa ilaa rabbinaa raaghiboon", english: "It may be that our Lord will give us in exchange a better (garden) than this: for we do turn to Him (in repentance)", romanUrdu: "Baeed (door) nahin ke hamara Rubb humein badle mein issey behtar baagh ata farmaye, hum apne Rubb ki taraf rujoo karte hain" },
    { number: 33, arabic: "كَذَٰلِكَ ٱلْعَذَابُ ۖ وَلَعَذَابُ ٱلْءَاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ", transliteration: "Kathalika alAAathabu walaAAathabu alakhirati akbaru law kanoo yaAAlamoona", transliterationB: "Kazaalikal azaab, wa la'azaabul aakhirati akbar; law kaanoo ya'lamoon", english: "Such is the Punishment (in this life); but greater is the Punishment in the Hereafter,- if only they knew", romanUrdu: "Aisa hota hai azaab aur aakhirat ka azaab issey bhi bada hai, kaash yeh log isko jaante" },
    { number: 34, arabic: "إِنَّ لِلْمُتَّقِينَ عِندَ رَبِّهِمْ جَنَّٰتِ ٱلنَّعِيمِ", transliteration: "Inna lilmuttaqeena AAinda rabbihim jannati alnnaAAeemi", transliterationB: "Inna lilmuttaqeena 'inda rabbihim jannaatin na'eem", english: "Verily, for the Righteous, are Gardens of Delight, in the Presence of their Lord", romanUrdu: "Yaqeenan khuda-tars logon ke liye unke Rubb ke yahan niyamat bhari jannatein hain" },
    { number: 35, arabic: "أَفَنَجْعَلُ ٱلْمُسْلِمِينَ كَٱلْمُجْرِمِينَ", transliteration: "AfanajAAalu almuslimeena kaalmujrimeena", transliterationB: "Afanaj'alul muslimeena kalmujrimeen", english: "Shall We then treat the People of Faith like the People of Sin", romanUrdu: "Kya hum farma-bardaaron ka haal mujreemon sa kardein" },
    { number: 36, arabic: "مَا لَكُمْ كَيْفَ تَحْكُمُونَ", transliteration: "Ma lakum kayfa tahkumoona", transliterationB: "Maa lakum kaifa tahhkumoon", english: "What is the matter with you? How judge ye", romanUrdu: "Tum logon ko kya ho gaya hai, tum kaise hukum lagate ho" },
    { number: 37, arabic: "أَمْ لَكُمْ كِتَٰبٌۭ فِيهِ تَدْرُسُونَ", transliteration: "Am lakum kitabun feehi tadrusoona", transliterationB: "Am lakum kitaabun feehi tadrusoon", english: "Or have ye a book through which ye learn", romanUrdu: "Kya tumhare paas koi kitaab hai jismein tum yeh padhte ho" },
    { number: 38, arabic: "إِنَّ لَكُمْ فِيهِ لَمَا تَخَيَّرُونَ", transliteration: "Inna lakum feehi lama takhayyaroona", transliterationB: "Inna lakum feehi lamaa takhaiyaroon", english: "That ye shall have, through it whatever ye choose", romanUrdu: "Ke tumhare liye zaroor wahan wahi kuch hai jo tum apne liye pasand karte ho" },
    { number: 39, arabic: "أَمْ لَكُمْ أَيْمَٰنٌ عَلَيْنَا بَٰلِغَةٌ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ ۙ إِنَّ لَكُمْ لَمَا تَحْكُمُونَ", transliteration: "Am lakum aymanun AAalayna balighatun ila yawmi alqiyamati inna lakum lama tahkumoona", transliterationB: "Am lakum aymaanun 'alainaa baalighatun ilaa yawmil qiyaamati inna lakum lamaa tahkumoon", english: "Or have ye Covenants with Us to oath, reaching to the Day of Judgment, (providing) that ye shall have whatever ye shall demand", romanUrdu: "Ya phir kya tumhare liye roz-e-qayamat tak humpar kuch ahad-o-paiman (covenant) sabit hai ke tumhein wahi kuch milega jiska tum hukum lagao" },
    { number: 40, arabic: "سَلْهُمْ أَيُّهُم بِذَٰلِكَ زَعِيمٌ", transliteration: "Salhum ayyuhum bithalika zaAAeemun", transliterationB: "Salhum ayyuhum bizaa lika za'eem", english: "Ask thou of them, which of them will stand surety for that", romanUrdu: "Inse pucho tum mein se kaun iska zaamin (gurantee/responsible) hai" },
    { number: 41, arabic: "أَمْ لَهُمْ شُرَكَآءُ فَلْيَأْتُوا۟ بِشُرَكَآئِهِمْ إِن كَانُوا۟ صَٰدِقِينَ", transliteration: "Am lahum shurakao falyatoo bishurakaihim in kanoo sadiqeena", transliterationB: "Am lahum shurakaaa'u falyaatoo bishurakaaa 'ihim in kaanoo saadiqeen", english: "Or have they some \"Partners\" (in Allahhead)? Then let them produce their \"partners\", if they are truthful", romanUrdu: "Ya phir inke thehraye huye kuch sahreek hain (jinhon ne iska zimma liya ho)?yeh baat hai to layein apne shareekon ko agar yeh sacchey hain" },
    { number: 42, arabic: "يَوْمَ يُكْشَفُ عَن سَاقٍۢ وَيُدْعَوْنَ إِلَى ٱلسُّجُودِ فَلَا يَسْتَطِيعُونَ", transliteration: "Yawma yukshafu AAan saqin wayudAAawna ila alssujoodi fala yastateeAAoona", transliterationB: "Yawma yukshafu 'am saaqinw wa yud'awna ilas sujoodi falaa yastatee'oon", english: "The Day that the shin shall be laid bare, and they shall be summoned to bow in adoration, but they shall not be able", romanUrdu: "Jis roz sakht waqt aa padega aur logon ko sajda karne ke liye bulaya jayega to yeh log sajda na kar sakenge" },
    { number: 43, arabic: "خَٰشِعَةً أَبْصَٰرُهُمْ تَرْهَقُهُمْ ذِلَّةٌۭ ۖ وَقَدْ كَانُوا۟ يُدْعَوْنَ إِلَى ٱلسُّجُودِ وَهُمْ سَٰلِمُونَ", transliteration: "KhashiAAatan absaruhum tarhaquhum thillatun waqad kanoo yudAAawna ila alssujoodi wahum salimoona", transliterationB: "Khaashi'atan absaaruhum tarhaquhum zillatunw wa qad kaanoo yud'awna ilassujoodi wa hum saalimoon", english: "Their eyes will be cast down,- ignominy will cover them; seeing that they had been summoned aforetime to bow in adoration, while they were whole, (and had refused)", romanUrdu: "Inki nigaahein nichey hongi, zillat inpar chaa rahi hogi. Yeh jab sahi-o-saalim thay us waqt inhein sajde ke liye (bulaya jata tha) aur yeh inkar karte thay" },
    { number: 44, arabic: "فَذَرْنِى وَمَن يُكَذِّبُ بِهَٰذَا ٱلْحَدِيثِ ۖ سَنَسْتَدْرِجُهُم مِّنْ حَيْثُ لَا يَعْلَمُونَ", transliteration: "Fatharnee waman yukaththibu bihatha alhadeethi sanastadrijuhum min haythu la yaAAlamoona", transliterationB: "Fazarnee wa many yukazzibu bihaazal hadeesi sanastad rijuhum min haisu laa ya'lamoon", english: "Then leave Me alone with such as reject this Message: by degrees shall We punish them from directions they perceive not", romanUrdu: "Pas aey Nabi, tum is kalam ke jhutlane walon ka maamla mujhpar chodh do hum aise tarike se inko batadreej tabahi ki taraf le jayenge ke inko khabar bhi na hogi" },
    { number: 45, arabic: "وَأُمْلِى لَهُمْ ۚ إِنَّ كَيْدِى مَتِينٌ", transliteration: "Waomlee lahum inna kaydee mateenun", transliterationB: "Wa umlee lahum; inna kaidee mateen", english: "A (long) respite will I grant them: truly powerful is My Plan", romanUrdu: "Main inki rassi daraaz kar raha hoon, meri chaal badi zabardast hai" },
    { number: 46, arabic: "أَمْ تَسْـَٔلُهُمْ أَجْرًۭا فَهُم مِّن مَّغْرَمٍۢ مُّثْقَلُونَ", transliteration: "Am tasaluhum ajran fahum min maghramin muthqaloona", transliterationB: "Am tas'aluhum ajran fahum mim maghramim musqaloon", english: "Or is it that thou dost ask them for a reward, so that they are burdened with a load of debt", romanUrdu: "Kya tum insey koi ajar (compensation) talab kar rahey ho ke yeh is chatti ke bojh (feel burdened with debt) taley dabey ja rahe hoon" },
    { number: 47, arabic: "أَمْ عِندَهُمُ ٱلْغَيْبُ فَهُمْ يَكْتُبُونَ", transliteration: "Am AAindahumu alghaybu fahum yaktuboona", transliterationB: "Am 'indahumul ghaibu fahum yaktuboon", english: "Or that the Unseen is in their hands, so that they can write it down", romanUrdu: "Kya inke paas gaib ka ilam hai jisey yeh likh rahey hon" },
    { number: 48, arabic: "فَٱصْبِرْ لِحُكْمِ رَبِّكَ وَلَا تَكُن كَصَاحِبِ ٱلْحُوتِ إِذْ نَادَىٰ وَهُوَ مَكْظُومٌۭ", transliteration: "Faisbir lihukmi rabbika wala takun kasahibi alhooti ith nada wahuwa makthoomun", transliterationB: "Fasbir lihkmi rabbika wa laa takun kasaahibil boot; iz naadaa wa huwa makzoom", english: "So wait with patience for the Command of thy Lord, and be not like the Companion of the Fish,- when he cried out in agony", romanUrdu: "Pas apne Rubb ka faisla saadir honay tak sabr karo aur machli wale (younis) ki tarah na ho jao, jab usne pukara tha aur woh gham se bhara hua tha" },
    { number: 49, arabic: "لَّوْلَآ أَن تَدَٰرَكَهُۥ نِعْمَةٌۭ مِّن رَّبِّهِۦ لَنُبِذَ بِٱلْعَرَآءِ وَهُوَ مَذْمُومٌۭ", transliteration: "Lawla an tadarakahu niAAmatun min rabbihi lanubitha bialAAarai wahuwa mathmoomun", transliterationB: "Law laaa an tadaara kahoo ni'matum mir rabbihee lanubiza bil'araaa'i wa huwa mazmoom", english: "Had not Grace from his Lord reached him, he would indeed have been cast off on the naked shore, in disgrace", romanUrdu: "Agar uske Rubb ki meharbani uske shamil-e-haal na ho jati to woh mazmoom (disgrace) hokar chatyal maidan mein phenk diya jata" },
    { number: 50, arabic: "فَٱجْتَبَٰهُ رَبُّهُۥ فَجَعَلَهُۥ مِنَ ٱلصَّٰلِحِينَ", transliteration: "Faijtabahu rabbuhu fajaAAalahu mina alssaliheena", transliterationB: "Fajtabaahu rabbuhoo faja'alahoo minas saaliheen", english: "Thus did his Lord choose him and make him of the Company of the Righteous", romanUrdu: "Aakhir-e-kaar uske Rubb ne usey barguzida (exalted) farma liya aur usey saleh bandon mein shamil kardiya" },
    { number: 51, arabic: "وَإِن يَكَادُ ٱلَّذِينَ كَفَرُوا۟ لَيُزْلِقُونَكَ بِأَبْصَٰرِهِمْ لَمَّا سَمِعُوا۟ ٱلذِّكْرَ وَيَقُولُونَ إِنَّهُۥ لَمَجْنُونٌۭ", transliteration: "Wain yakadu allatheena kafaroo layuzliqoonaka biabsarihim lamma samiAAoo alththikra wayaqooloona innahu lamajnoonun", transliterationB: "Wa iny-yakaadul lazeena kafaroo la-yuzliqoonaka biabsaarihim lammaa saml'uz-Zikra wa yaqooloona innahoo lamajnoon", english: "And the Unbelievers would almost trip thee up with their eyes when they hear the Message; and they say: \"Surely he is possessed", romanUrdu: "Jab yeh kafir log kalam-e-nasihat (Quran) sunte hain to tumhein aisi nazaron se dekhte hain ke goya tumhare qadam ukhaad denge, Aur kehte hain ke yeh zaroor deewana hai" },
    { number: 52, arabic: "وَمَا هُوَ إِلَّا ذِكْرٌۭ لِّلْعَٰلَمِينَ", transliteration: "Wama huwa illa thikrun lilAAalameena", transliterationB: "Wa maa huwa illaa zikrul lil'aalameen", english: "But it is nothing less than a Message to all the worlds", romanUrdu: "Halaanke yeh to sarey jahaan walon ke liye ek naseehat hai" }
  ]
};
